('0d775ba4-7cc4-4e1a-96ff-83da87d1995d', 'SK2', 'Mampu mengaplikasikan bidang keahliannya dan memanfaatkan IPTEKS pada bidangnya dalam penyelesaian masalah serta mampu beradaptasi terhadap situasi yang dihadapi', 'Sikap Khusus', 1, '2026-05-14 10:20:24.214', '2026-05-14 10:20:24.214', NULL, '0b198d68-4f78-11f1-9b2e-fabbba741406', 'e767ee45-6d69-46d5-bd3f-d75aa378ff26', 'bc729d21-47b8-413f-b1d0-e758a297e98d'),
('1cf1c0e7-7d6d-40f1-9f85-ac5323b2e301', 'KK17', 'Menerapkan konsep-konsep yang berkaitan dengan pengembangan berbasis platform serta mampu mengembangkan program aplikasi berbasis platform untuk berbagai area', 'Keterampilan Khusus', 1, '2026-05-14 10:20:25.080', '2026-05-14 10:20:25.080', NULL, '0b198fb8-4f78-11f1-9b2e-fabbba741406', 'e767ee45-6d69-46d5-bd3f-d75aa378ff26', 'bc729d21-47b8-413f-b1d0-e758a297e98d'),
