('23ce2128-9d99-4fed-ac68-739da29fe2be', 'SK5', 'Bertanggung jawab pada pekerjaan sendiri dan dapat diberi tanggung jawab atas pencapaian hasil kerja organisasi', 'Sikap Khusus', 1, '2026-05-14 10:20:24.277', '2026-05-14 10:20:24.277', NULL, '0b198d68-4f78-11f1-9b2e-fabbba741406', 'e767ee45-6d69-46d5-bd3f-d75aa378ff26', 'bc729d21-47b8-413f-b1d0-e758a297e98d'),
