('2c717a67-8191-4356-bd33-6fd648db8e01', 'e767ee45-6d69-46d5-bd3f-d75aa378ff26', 1, 'Pada Tahun 2035, menjadi Program Studi Informatika berdaya saing Internasional pada bidang Internet of Things, Software Development, dan High Performance Computing yang berkarakter dan inspiratif', 'visi', 1, '2026-05-14 08:25:48.582', '2026-05-14 08:53:05.640'),
('ddbe139c-6fe9-44bb-ae4d-f8a9a3ffacd7', 'e767ee45-6d69-46d5-bd3f-d75aa378ff26', 3, 'engembangkan penelitian bidang informatika secara implementatif sebagai program pengabdian kepada masyarakat yang bekelanjutan dan mendukung kearifan lokal', 'misi', 1, '2026-05-14 08:53:05.695', '2026-05-14 08:53:05.695'),
